/**
 * @summary Save settings (upsert)
 */
export const getSaveSettingsUrl = () => {
  return `/api/settings`;
};

export const saveSettings = async (
  saveSettingsBody: SaveSettingsBody,
  options?: RequestInit,
): Promise<Setting[]> => {
  return customFetch<Setting[]>(getSaveSettingsUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(saveSettingsBody),
  });
};

export const getSaveSettingsMutationOptions = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof saveSettings>>,
    TError,
    { data: BodyType<SaveSettingsBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof saveSettings>>,
  TError,
  { data: BodyType<SaveSettingsBody> },
  TContext
> => {
  const mutationKey = ["saveSettings"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof saveSettings>>,
    { data: BodyType<SaveSettingsBody> }
  > = (props) => {
    const { data } = props ?? {};

    return saveSettings(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SaveSettingsMutationResult = NonNullable<
  Awaited<ReturnType<typeof saveSettings>>
>;
export type SaveSettingsMutationBody = BodyType<SaveSettingsBody>;
export type SaveSettingsMutationError = ErrorType<ErrorResponse>;

